"""
MKT Christ Commentary — Isaiah 19 (25 verses — The Oracle Against Egypt)
Run: python3 scripts/zc-christ-isaiah-19.py
Key decisions:
- v1: YHWH rides on a swift cloud — type: Rev 1:7 / Matt 24:30 (Christ coming
  on clouds); cloud-riding is divine theophany attributed to Christ
- v20: mosiah (H3467, savior/deliverer) sent to Egypt — direct messianic type:
  the savior sent to deliver the oppressed is the Christ pattern
- v22: YHWH strikes-and-heals Egypt — the paradox answered in Christ: John
  12:32 (Christ's lifting up draws all, including Gentiles/Egyptians)
- vv23-25: Egypt-Assyria-Israel highway of peace — the reconciliation of
  former enemies; Eph 2:14 (Christ making the two into one); the Gentile
  mission; the triple covenant blessing extended to historic enemies of Israel
- v18: Cities speak the language of Canaan — the covenant language spreading
  to Egypt; Acts 2:8-11 (the Pentecost miracle of languages)
- vv19-22: Altar in Egypt, knowledge of YHWH, healing — fulfilled in the
  early church's mission to Egypt (Acts 8:26-40 Philip and the Ethiopian;
  the Coptic church founded by Mark)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys so re-running is safe after manual edits.
    # CHANGE? If isaiah.json schema changes, update merge_comm and ISAIAH dict below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
    #   isaiah.json')); print('Isa 19 v20:',d.get('19',{}).get('20','MISSING')[:80])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


ISAIAH = {
    "19": {
        "1": "<p>\"Behold, the LORD is riding on a swift cloud and comes to Egypt; and the idols of Egypt will tremble at his presence\" — YHWH enthroned on the cloud, advancing on the empire. The cloud-riding is the theophany of the divine warrior (Ps 68:4: \"Extol him who rides on the clouds\"). Revelation 1:7: \"Look, he is coming with the clouds, and every eye will see him.\" Matthew 24:30: \"they will see the Son of Man coming on the clouds of heaven, with power and great glory.\" The YHWH who rides the cloud to judge Egypt is the Christ who comes on the clouds at the end of the age — the divine warrior who shakes every false sovereignty. What YHWH does to Egypt's idols he will do at last to every idol of every age.</p>",
        "2": "<p>\"And I will stir up Egyptians against Egyptians, and they will fight, each against his brother and each against his neighbor, city against city, kingdom against kingdom\" — YHWH as the one who, in judgment, allows a society to tear itself apart through internal division. The removal of YHWH's preserving hand reveals the inherent fragility of human social order. Luke 12:51-53: \"Do you think I came to bring peace on earth? No, I tell you, but division.\" Matthew 10:35-36: \"I have come to turn a man against his father, a daughter against her mother.\" Christ's coming, like YHWH's coming to Egypt, does not create the division but reveals it — the sword of the gospel exposes where loyalties already lie, and the resulting divisions make visible what was already present.</p>",
        "3": "<p>\"And the spirit of the Egyptians within them will be emptied out, and I will confound their counsel\" — the divine emptying of human wisdom and spirit: Egypt's renowned wisdom traditions dismantled. 1 Corinthians 1:20: \"Where is the wise person? Where is the teacher of the law? Where is the philosopher of this age? Has not God made foolish the wisdom of the world?\" The confounding of Egypt's counsel in Isaiah 19:3 is the OT pattern that Paul applies to the cross: the wisdom of the cross dismantles every human wisdom tradition, including Egypt's millennia-old scholarship. \"They will consult the idols and the sorcerers, and the mediums and the necromancers\" — each rejected resource named and exposed as inadequate.</p>",
        "4": "<p>\"And I will give over the Egyptians into the hand of a hard master, and a fierce king will rule over them, declares the Lord, the LORD of Hosts\" — the judgment by subjection: the free empire becomes the enslaved empire; the enslaver becomes the enslaved. The reversal of Exodus: now the Egyptians experience what they inflicted. The \"hard master\" (<em>ʾădōnîm qāšeh</em>) recalls the Egyptian taskmaster vocabulary of Exodus. Luke 1:52: \"He has brought down rulers from their thrones but has lifted up the humble.\" The Magnificat's language of reversal (rulers brought down, humble lifted) is the same divine pattern applied by Isaiah to Egypt: the nation that enslaved Israel is itself enslaved.</p>",
        "5": "<p>\"And the waters of the sea will be dried up, and the river will be parched and dry\" — the Nile drying up is the comprehensive judgment on Egypt's economic and spiritual foundation: Egypt's civilization was built on the Nile's annual flooding. The drying of the Nile reverses what made Egypt Egypt. Revelation 16:12: \"The sixth angel poured out his bowl on the great river Euphrates, and its water was dried up to prepare the way for the kings from the East.\" The eschatological drying of the great river in Revelation mirrors the historic drying of the Nile in Isaiah — both are divine acts that dismantle empires built on particular rivers, preparing the way for a new order.</p>",
        "6": "<p>\"And the canals will become foul, and the branches of Egypt's Nile will diminish and dry up\" — the interconnected hydraulic system of Egypt failing at every channel. The branches that carried Nile water to fields and cities will become stagnant and dry. Revelation 22:1-2: \"the river of the water of life... flowing from the throne of God and of the Lamb.\" The dying canals of Egypt (judgment) are answered by the living river of the new Jerusalem (grace): what YHWH takes from those who reject him, he gives in abundance to those who receive him through Christ. The water that fails in judgment flows eternal in the new creation.</p>",
        "7": "<p>\"There will be bare places by the Nile, on the brink of the Nile, and all that is sown by the Nile will be parched, will be driven away, and will be no more\" — the agricultural devastation: the Nile-fed fields becoming desert. Egypt's agricultural abundance was its pride and power. John 6:35: \"I am the bread of life; whoever comes to me will never go hungry.\" The fields that fail in Isaiah 19:7 point toward the one who is himself the sustaining bread: what the Nile's water sustained in the physical-agricultural realm, Christ sustains in the spiritual-eternal realm — and will sustain in the bodily-resurrection realm of the new creation.</p>",
        "8": "<p>\"The fishermen will mourn and lament, all who cast a hook in the Nile; and those who spread nets on the water will languish\" — the fishing industry mourning as the fish die with the Nile. Revelation 18:17-19: the mariners and merchants mourning over Babylon's fall — \"every sea captain, and all who travel by ship... will stand far off and cry out when they see the smoke of her burning.\" The mourning of Egypt's fishermen in Isaiah 19:8 is the type of the mourning of those whose economic lives were built on the doomed empire. But the gospel turns mourning fishermen into the first disciples: Matthew 4:19 (\"Follow me, and I will make you fishers of men\").</p>",
        "9": "<p>\"Those who work in combed flax will be in despair, and the weavers of white cotton\" — the textile workers who made Egypt's famous linen (the fabric of the priestly garments, Ex 28; the burial shroud of the wealthy) mourning as the raw materials fail. Revelation 19:8: \"Fine linen, bright and clean, was given her to wear. (Fine linen stands for the righteous acts of God's holy people.)\" The linen that Egypt's weavers produced for earthly honor is the type of the righteous-acts linen of the bride of Christ — what the doomed empire manufactured for earthly display, Christ gives his people as the garment of their eternal identity.</p>",
        "10": "<p>\"Those who are the pillars of the land will be crushed, and all who work for pay will be grieved\" — the social infrastructure collapsing: the foundational workers who hold the economic structure in place are crushed. Matthew 7:27: \"The rain came down, the streams rose, and the winds blew and beat against that house, and it fell with a great crash.\" The pillars of Egypt crushed in Isaiah 19:10 are the pillars of the house built on sand — every human structure that does not rest on the rock of Christ will fall (Matt 7:24-27). The one who builds on the rock survives what destroys those built on the sand of human power.</p>",
        "11": "<p>\"The princes of Zoan are utterly foolish; the wise counselors of Pharaoh give stupid counsel. How can you say to Pharaoh, 'I am a son of the wise, a son of ancient kings'?\" — the collapse of Egypt's wisdom-credentials: the famous wise men who claimed lineage from ancient sages are shown to be fools. 1 Corinthians 1:19: \"For it is written: 'I will destroy the wisdom of the wise; the intelligence of the intelligent I will frustrate.'\" The foolishness of Pharaoh's counselors in Isaiah 19:11 is the OT form of Paul's argument: the cross exposes all human wisdom as inadequate, particularly the wisdom of those who claim the most ancient and sophisticated traditions.</p>",
        "12": "<p>\"Where then are your wise men? Let them tell you, let them know what the LORD of Hosts has purposed against Egypt\" — the challenge to Egypt's wisdom tradition to explain YHWH's purposes: they cannot. The divine plan is hidden from human wisdom and requires revelation. 1 Corinthians 2:7-8: \"we declare God's wisdom, a mystery that has been hidden... which none of the rulers of this age understood, for if they had, they would not have crucified the Lord of glory.\" The wise men who could not know what YHWH purposed against Egypt are the type of the \"rulers of this age\" who did not know the mystery of Christ — the wisdom hidden from the wise and revealed to the childlike (Matt 11:25).</p>",
        "13": "<p>\"The princes of Zoan have become fools, and the princes of Memphis are deluded; those who are the cornerstones of her tribes have led Egypt astray\" — the deluded leaders who mislead the nation. Psalm 118:22: \"The stone the builders rejected has become the cornerstone.\" The \"cornerstones of Egypt's tribes\" who have become deluded and lead astray contrast with the true cornerstone rejected by human builders: Christ (1 Pet 2:6-7; Eph 2:20). Egypt's failed cornerstones are the negative backdrop against which the one true cornerstone is displayed — the rejected stone becomes the only stable foundation for the new community.</p>",
        "14": "<p>\"The LORD has mingled within her a spirit of confusion, and they have made Egypt stagger in all its deeds, as a drunken man staggers in his vomit\" — the spirit of confusion (<em>rûaḥ ʿiwʿîm</em>) as divine judgment on Egypt's wisdom tradition: the very capacity for clear thought is impaired. Isaiah 51:17 described Jerusalem drinking the cup of staggering; now Egypt staggers in its own vomit. 2 Thessalonians 2:11: \"For this reason God sends them a powerful delusion so that they will believe the lie.\" The judicial confusion of Isaiah 19:14 and the powerful delusion of 2 Thessalonians 2:11 operate by the same divine logic: the persistent rejection of truth is judged by an inability to perceive it.</p>",
        "15": "<p>\"And there will be nothing for Egypt that head or tail, palm branch or reed, may do\" — the comprehensive incapacitation: every level of leadership (head/tail = great/small; palm/reed = noble/humble) is rendered useless. Isaiah 9:14-15 used the same head/tail language for Israel's failed leadership. The parallel is intentional: Egypt and Israel receive the same judgment-structure when they abandon YHWH. Acts 17:26-27: God \"made from one man every nation of mankind... that they should seek God.\" Egypt, like Israel, was made to seek the living God — and the judgment on Egypt's failed leadership points toward the one true Leader who succeeds where all human leaders fail.</p>",
        "16": "<p>\"In that day the Egyptians will be like women, and tremble with fear before the hand that the LORD of Hosts shakes over them\" — the \"in that day\" section begins (vv16-25), shifting from judgment to eschatological transformation. The trembling that is initially fear before divine judgment becomes the trembling that precedes conversion. Philippians 2:12: \"work out your salvation with fear and trembling.\" The reverent fear that marks the redeemed community is the conversion of the trembling that precedes it: the same shaking hand of YHWH (v16) that terrifies Egypt in judgment is the hand that will be recognized as saving in vv20-22. Fear is the beginning of wisdom and the beginning of conversion.</p>",
        "17": "<p>\"And the land of Judah will become a terror to the Egyptians. Everyone to whom it is mentioned will fear because of the purpose that the LORD of Hosts has purposed against them\" — Judah as the source of Egypt's fear: the small nation through whom YHWH's purposes run becomes the focus of Egyptian dread. This anticipates the pattern of the church: Colossians 1:27 (\"Christ in you, the hope of glory\") — the small community that carries the covenant name becomes the presence of the divine purpose to the watching nations. The land of Judah that terrifies Egypt is the type of the gospel community that brings both fear and hope to the world.</p>",
        "18": "<p>\"In that day there will be five cities in the land of Egypt that speak the language of Canaan and swear allegiance to the LORD of Hosts\" — the covenant language spreading to Egypt: five Egyptian cities speaking Hebrew, the language of the covenant people. Acts 2:8-11: at Pentecost, \"each one heard them speaking in his own language\" — the miracle of language reversed: at Sinai, one language given to one people; at Pentecost, the gospel spoken in every language; in the fulfillment of Isaiah 19:18, Egypt's cities speak the covenant language. The \"language of Canaan\" that spreads to Egypt is the language of the covenant community — fulfilled when the gospel of the covenant's fulfilment spreads to all nations (Matt 28:19).</p>",
        "19": "<p>\"In that day there will be an altar to the LORD in the midst of the land of Egypt, and a pillar to the LORD at its border\" — worship of YHWH established in Egypt's heart and boundary: the entire land bracketed by covenant markers. The altar at the center and the pillar at the border enclose all of Egypt within the covenant. Acts 8:26-40: Philip and the Ethiopian eunuch — the gospel reaches Africa/Egypt through this encounter. The early church's tradition places Mark as the founder of the Egyptian church. The altar in Egypt's midst prophesied in Isaiah 19:19 is fulfilled in the Coptic church and the millennia of Egyptian Christianity — the covenant worship established in the empire that enslaved Israel.</p>",
        "20": "<p>\"It will be a sign and a witness to the LORD of Hosts in the land of Egypt. When they cry to the LORD because of oppressors, he will send them a savior (<em>môšîaʿ</em>) and a defender, and deliver them\" — the messianic language embedded in the promise to Egypt: YHWH will send a <em>môšîaʿ</em> (savior/deliverer, H3467) — the same word-root as Joshua/Yeshua/Jesus. The Egyptians who cry to YHWH under oppression will receive a savior sent from YHWH. Luke 4:18: \"to proclaim release to the oppressed.\" Acts 7:25: Stephen explains Moses's self-understanding — \"Moses thought that his own people would realize that God was using him to rescue them.\" The pattern of the sent-savior runs from Moses through the judge-saviors of Israel to its fullest expression in Jesus — the one whose very name means YHWH saves.</p>",
        "21": "<p>\"And the LORD will make himself known to the Egyptians, and the Egyptians will know the LORD in that day and worship with sacrifice and offering, and they will make vows to the LORD and perform them\" — the Gentile knowledge and worship of YHWH: Egypt not merely spared but converted, not merely worshiping but fulfilling vows. John 17:3: \"Now this is eternal life: that they know you, the only true God, and Jesus Christ, whom you have sent.\" The Egyptians who \"know the LORD\" in Isaiah 19:21 are the Gentiles who come to know the Father through the Son — the missionary expansion that carries the gospel from Jerusalem to Egypt, just as Acts traces (the Ethiopian in Acts 8, Philip's move southward). The fullness of the Gentile harvest includes Egypt specifically.</p>",
        "22": "<p>\"And the LORD will strike Egypt, striking and healing, and they will return to the LORD, and he will listen to their pleas for mercy and heal them\" — the paradox of divine judgment and healing: YHWH strikes Egypt and heals Egypt. The strike-and-heal pattern is the covenant discipline structure: Deuteronomy 32:39 (\"I kill and I make alive; I wound and I heal\"). John 3:14-15: \"Just as Moses lifted up the snake in the wilderness, so the Son of Man must be lifted up, that everyone who believes may have eternal life.\" The healing of Egypt in Isaiah 19:22 is the same healing as the bronze snake in the wilderness — the divine wound that becomes the occasion for divine healing, with the healer now identified as the lifted-up Son of Man.</p>",
        "23": "<p>\"In that day there will be a highway from Egypt to Assyria, and Assyria will come into Egypt, and Egypt into Assyria, and the Egyptians will worship with the Assyrians\" — the great reconciliation: the two great historic enemies of Israel joined together in covenant worship. Egypt and Assyria had been the twin threats that crushed the ancient Near East between them — now they share a highway of peace. Ephesians 2:14-15: \"For he himself is our peace, who has made the two groups one and has destroyed the barrier, the dividing wall of hostility... to create in himself one new humanity out of the two.\" Paul applies Jew-Gentile reconciliation; Isaiah's Egypt-Assyria reconciliation is the OT type. Christ is the highway (John 14:6: \"I am the way\") that joins enemies.</p>",
        "24": "<p>\"In that day Israel will be the third with Egypt and Assyria, a blessing in the midst of the earth\" — the three-way covenant community: former enemies made into a single blessing in the midst of the earth. Israel is not the center but the \"third\" — joined between two Gentile nations. Galatians 3:28-29: \"There is neither Jew nor Gentile... for you are all one in Christ Jesus. If you belong to Christ, then you are Abraham's seed, and heirs according to the promise.\" The joining of Israel with Egypt and Assyria in Isaiah 19:24 is the anticipation of the one new humanity in Christ — the middle wall of hostility torn down, former enemies made fellow heirs of the covenant blessing.</p>",
        "25": "<p>\"Whom the LORD of Hosts has blessed, saying, 'Blessed is Egypt my people, and Assyria the work of my hands, and Israel my inheritance'\" — the triple blessing: the covenant-names of YHWH's possession (<em>ʿammî</em>, \"my people\"; <em>maʿăśeh yādāyw</em>, \"work of my hands\"; <em>naḥălātî</em>, \"my inheritance\") distributed across three formerly-rival nations. Egypt receives \"my people\" — the name YHWH gave Israel at the Exodus. Assyria receives \"the work of my hands\" — the language of creation. Israel receives \"my inheritance.\" Romans 15:10-11: Paul's Gentile-inclusion catena cites \"Praise the LORD, all you Gentiles; let all the peoples extol him\" (quoting Ps 117:1). The ultimate answer to the oracle against Egypt (v1) is the oracle of blessing over Egypt (v25) — the nation that enslaved Israel becomes the nation YHWH calls \"my people.\" Christ's death breaks down every wall that would prevent this triple blessing.</p>"
    }
}


def main():
    existing = load_comm("mkt-christ", "isaiah")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, ISAIAH)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "isaiah", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("1", "cloud"), ("20", "savior"), ("23", "highway"), ("25", "blessed")]:
        entry = existing.get("19", {}).get(v, "MISSING")
        print(f"  Isa 19:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    ch = existing.get("19", {})
    missing = [str(i) for i in range(1, 26) if str(i) not in ch]
    print(f"  Missing verses: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
